<?php session_start(); require __DIR__ . "/php/connect.php"; $error = ""; if ($_SERVER["REQUEST_METHOD"] === "POST") { $email = filter_input(INPUT_POST, "email", FILTER_VALIDATE_EMAIL); $password = $_POST["password"] ?? ""; $stmt = $mysqli->prepare("SELECT id, full_name, password_hash, created_at FROM demo_users WHERE email = ?"); $stmt->bind_param("s", $email); $stmt->execute(); $user = $stmt->get_result()->fetch_assoc(); if ($user && password_verify($password, $user["password_hash"])) { $_SESSION["demo_user"] = $user; header("Location: dashboard.php"); exit; } $error = "Invalid login."; } ?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Scenario B Login</title><link rel="stylesheet" href="css/styles.css"></head><body><header><h1>Scenario B Login</h1><nav><a href="index.php">Contact</a><a href="register.php" class="secondary">Register</a></nav></header><main><form method="post"><h2>Login</h2><?php if ($error): ?><div class="message error"><?= htmlspecialchars($error) ?></div><?php endif; ?><label>Email</label><input type="email" name="email" required><label>Password</label><input type="password" name="password" required><div class="actions"><button>Login</button></div></form></main><footer><p>CISC3003 Web Programming: Kris Wu Zexian + DC228114 + 2026</p></footer></body></html>
